INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article1.desc', 'es', '¿Cansado de bajar del autobús turístico, tomar una foto y volver a subir? Tourgether te permite experimentar joyas ocultas que solo los locales conocen, restaurantes auténticos y la verdadera atmósfera de cada ciudad. Conéctate directamente con guías locales y planifica tu propio viaje personalizado.', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article1.title', 'es', 'Dile adiós a los tours empaquetados aburridos', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article2.desc', 'es', '¿Quieres viajar solo pero te preocupa comer solo o no tener a nadie que te tome fotos? Usa nuestra función "Open to Meet" para encontrar otros viajeros en la misma zona. Comparte comidas, tours y actividades con personas afines y despídete de la soledad del viaje en solitario.', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article2.title', 'es', 'Una plataforma de conexión para viajeros solitarios', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article3.desc', 'es', 'Nadie conoce tu ciudad mejor que tú. Conviértete en guía local en Tourgether, ofrece experiencias únicas a los viajeros y genera ingresos. Registra diversos servicios como tours gastronómicos, servicios de fotografía, acompañamiento de compras e interpretación de idiomas.', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article3.title', 'es', 'Una economía colaborativa donde los locales pueden ganar', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article4.desc', 'es', 'Opera con confianza usando nuestro sistema de pago con custodia. Los fondos se mantienen seguros hasta que se complete el servicio, y nuestro sistema de resolución de disputas protege a ambas partes. Encuentra socios confiables fácilmente a través de reseñas y distintivos de anfitriones verificados.', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article4.title', 'es', 'Sistema de transacción P2P seguro', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article5.desc', 'es', 'Comparte tus momentos de viaje con fotos en el feed y visualiza tu recorrido en una línea de tiempo basada en mapas. Nuestra función CineMap impulsada por IA analiza los datos de ubicación de las fotos para crear automáticamente storyboards de viaje cinematográficos.', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article5.title', 'es', 'Preserva hermosamente tus recuerdos de viaje', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.subtitle', 'es', 'Una nueva forma de redescubrir la esencia del viaje', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.title', 'es', '¿Por qué Tourgether?', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
