INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'guide.viewDetails', 'fr', 'Voir les détails', true, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article1.desc', 'fr', 'Fatigué de descendre du bus touristique, de prendre une photo et de remonter ? Tourgether vous permet de découvrir des endroits cachés que seuls les locaux connaissent, des restaurants authentiques et la vraie atmosphère de chaque ville. Connectez-vous directement avec des guides locaux et planifiez votre propre voyage sur mesure.', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article1.title', 'fr', 'Dites adieu aux voyages organisés monotones', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article2.desc', 'fr', 'Envie de voyager seul mais inquiet de manger seul ou de n''avoir personne pour prendre vos photos ? Utilisez notre fonction "Open to Meet" pour rencontrer d''autres voyageurs dans la même région. Partagez repas, visites et activités avec des personnes partageant les mêmes intérêts.', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article2.title', 'fr', 'Une plateforme de connexion pour les voyageurs solo', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article3.desc', 'fr', 'Personne ne connaît votre ville mieux que vous. Devenez guide local sur Tourgether, offrez des expériences uniques aux voyageurs et gagnez de l''argent. Enregistrez divers services comme des tours gastronomiques, des services photo, l''accompagnement shopping et l''interprétation linguistique.', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article3.title', 'fr', 'Une économie de partage où les locaux peuvent gagner', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article4.desc', 'fr', 'Effectuez vos transactions en toute confiance grâce à notre système de paiement séquestre. Les fonds sont conservés en sécurité jusqu''à la fin du service, et notre système de résolution des litiges protège les deux parties. Trouvez facilement des partenaires fiables grâce aux avis et aux badges d''hôtes vérifiés.', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article4.title', 'fr', 'Système de transaction P2P sécurisé', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article5.desc', 'fr', 'Partagez vos moments de voyage avec des photos sur le fil et visualisez votre parcours sur une timeline basée sur une carte. Notre fonction CineMap alimentée par l''IA analyse les données de localisation des photos pour créer automatiquement des storyboards de voyage cinématographiques.', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article5.title', 'fr', 'Préservez magnifiquement vos souvenirs de voyage', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.subtitle', 'fr', 'Une nouvelle façon de redécouvrir l''essence du voyage', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.title', 'fr', 'Pourquoi Tourgether ?', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
