INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article1.desc', 'zh', '厌倦了从大巴下来拍一张照片又上车的旅行吗？Tourgether让您体验只有当地人才知道的隐藏景点、地道美食和真正的城市氛围。直接与当地导游联系，规划属于您的定制旅行。', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article1.title', 'zh', '告别千篇一律的跟团游', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article2.desc', 'zh', '想独自旅行但担心一个人吃饭，或者没人帮您拍照？使用"Open to Meet"功能，在同一地区找到其他旅行者。与志同道合的人一起用餐、旅游和活动，告别独行的孤独。', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article2.title', 'zh', '为独行旅者打造的社交平台', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article3.desc', 'zh', '没有人比您更了解您的城市。在Tourgether成为当地导游，为旅行者提供独特体验并获得收入。可以注册美食游、摄影服务、陪同购物、语言翻译等各种服务。', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article3.title', 'zh', '当地人也能赚钱的共享经济', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article4.desc', 'zh', '通过托管支付系统安心交易。服务完成前资金安全保管，如有问题，争议解决系统保护双方。通过评价系统和认证徽章轻松找到可信赖的对象。', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article4.title', 'zh', '安全的P2P交易系统', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article5.desc', 'zh', '在动态中分享带照片的旅行瞬间，用地图时间轴可视化您的旅程。AI驱动的CineMap功能分析照片位置信息，自动生成电影般的旅行故事板。旅行结束后也能轻松回顾美好回忆。', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article5.title', 'zh', '精美记录您的旅行回忆', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.subtitle', 'zh', '找回旅行本质的新方式', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.title', 'zh', '为什么选择Tourgether？', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
